"""
IoT State Machine Implementation in Python
Demonstrates logical design of state-based IoT systems
"""
from abc import ABC, abstractmethod
from typing import Dict, List, Callable, Optional, Tuple
from enum import Enum
import time

# Define states as enum for type safety
class TrafficLightState(Enum):
 RED = "red"
 YELLOW = "yellow"
 GREEN = "green"

# Event types
class Event:
 def __init__(self, event_type: str, data: dict = None):
 self.event_type = event_type
 self.data = data or {}

# Abstract State Handler
class StateHandler(ABC):
 @abstractmethod
 def on_enter(self):
 pass

 @abstractmethod
 def on_exit(self):
 pass

# Concrete State Handlers
class RedStateHandler(StateHandler):
 def on_enter(self):
 print("🚦 RED LIGHT - Stop vehicles")

 def on_exit(self):
 print(" Exiting RED state")

class YellowStateHandler(StateHandler):
 def on_enter(self):
 print("🚦 YELLOW LIGHT - Prepare to stop")

 def on_exit(self):
 print(" Exiting YELLOW state")

class GreenStateHandler(StateHandler):
 def on_enter(self):
 print("🚦 GREEN LIGHT - Go!")

 def on_exit(self):
 print(" Exiting GREEN state")

# Main State Machine Class
class IoTStateMachine:
 def __init__(self, name: str):
 self.name = name
 self.states: Dict[str, StateHandler] = {}
 self.transitions: Dict[str, Dict[str, Tuple[str, Callable]]] = {}
 self.current_state: Optional[str] = None
 self.history: List[str] = []

 def add_state(self, state_name: str, handler: StateHandler):
 """Register a state with its handler"""
 self.states[state_name] = handler
 self.transitions[state_name] = {}

 def add_transition(self, from_state: str, event: str, 
 to_state: str, action: Callable = None):
 """Define a valid state transition"""
 if from_state in self.transitions:
 self.transitions[from_state][event] = (to_state, action)

 def set_initial_state(self, state_name: str):
 """Set the starting state"""
 self.current_state = state_name
 if state_name in self.states:
 self.states[state_name].on_enter()
 self.history.append(state_name)

 def process_event(self, event: Event) -> str:
 """Process an event and transition if valid"""
 if self.current_state not in self.transitions:
 return self.current_state

 transitions = self.transitions[self.current_state]

 if event.event_type in transitions:
 next_state, action = transitions[event.event_type]

 # Execute exit handler
 self.states[self.current_state].on_exit()

 # Execute transition action
 if action:
 action(event)

 # Transition to new state
 self.current_state = next_state
 self.history.append(next_state)

 # Execute enter handler
 self.states[next_state].on_enter()

 return self.current_state

 def get_current_state(self) -> Optional[str]:
 return self.current_state

 def verify_safety_property(self) -> bool:
 """Safety: Always in a valid state"""
 return self.current_state in self.states

 def verify_liveness_property(self) -> bool:
 """Liveness: All states visited eventually"""
 return all(s in self.history for s in self.states.keys())

# Transition action function
def log_transition(event: Event):
 print(f" → Transition triggered by: {event.event_type}")

# Factory function to create traffic light
def create_traffic_light() -> IoTStateMachine:
 machine = IoTStateMachine("Traffic Light")

 # Add states
 machine.add_state("red", RedStateHandler())
 machine.add_state("yellow", YellowStateHandler())
 machine.add_state("green", GreenStateHandler())

 # Add transitions with cycle times
 machine.add_transition("red", "TIMER_EXPIRED", "green", log_transition)
 machine.add_transition("green", "TIMER_EXPIRED", "yellow", log_transition)
 machine.add_transition("yellow", "TIMER_EXPIRED", "red", log_transition)

 # Emergency transitions
 machine.add_transition("green", "EMERGENCY", "red", log_transition)
 machine.add_transition("yellow", "EMERGENCY", "red", log_transition)
 machine.add_transition("red", "EMERGENCY", "red", log_transition)

 return machine

# Demo execution
if __name__ == "__main__":
 print("=" * 50)
 print("IoT State Machine - Traffic Light Demo")
 print("=" * 50)

 # Create and initialize traffic light
 traffic_light = create_traffic_light()
 traffic_light.set_initial_state("red")

 print("\n--- Simulating traffic light cycle ---\n")

 # Simulate state transitions
 events = [
 Event("TIMER_EXPIRED"),
 Event("TIMER_EXPIRED"),
 Event("TIMER_EXPIRED"),
 Event("TIMER_EXPIRED"),
 ]

 for e in events:
 time.sleep(0.5) # Short delay for demo
 traffic_light.process_event(e)

 print("\n--- Testing Emergency Transition ---\n")
 traffic_light.process_event(Event("EMERGENCY"))

 print("\n--- Property Verification ---")
 print(f"Safety Property (valid state): {traffic_light.verify_safety_property()}")
 print(f"Liveness Property (all states visited): {traffic_light.verify_liveness_property()}")
 print(f"State History: {traffic_light.history}")

"""
Event-Driven IoT Architecture
Implements Publisher-Subscribe pattern for decoupled component communication
"""
from typing import Dict, List, Callable, Any, Set
from dataclasses import dataclass, field
from datetime import datetime
from abc import ABC, abstractmethod
import threading
import time
import random

# ============================================
# Event System Components
# ============================================

@dataclass
class Event:
 """Base event class for IoT system events"""
 event_type: str
 source: str
 timestamp: datetime = field(default_factory=datetime.now)
 data: Dict = field(default_factory=dict)

 def __str__(self):
 return f"Event({self.event_type} from {self.source} at {self.timestamp.strftime('%H:%M:%S')})
"

class EventListener(ABC):
 """Abstract listener interface"""
 @abstractmethod
 def on_event(self, event: Event):
 pass

 @property
 @abstractmethod
 def listener_name(self) -> str:
 pass

class EventManager:
 """
 Central Event Manager - Publish/Subscribe Pattern
 Allows loose coupling between IoT components
 """

 def __init__(self):
 self.listeners: Dict[str, List[EventListener]] = {}
 self.event_history: List[Event] = []
 self.lock = threading.Lock()

 def subscribe(self, event_type: str, listener: EventListener):
 """Subscribe a listener to a specific event type"""
 with self.lock:
 if event_type not in self.listeners:
 self.listeners[event_type] = []
 if listener not in self.listeners[event_type]:
 self.listeners[event_type].append(listener)
 print(f"✓ {listener.listener_name} subscribed to {event_type}")

 def unsubscribe(self, event_type: str, listener: EventListener):
 """Remove a listener from an event type"""
 with self.lock:
 if event_type in self.listeners:
 self.listeners[event_type].remove(listener)

 def publish(self, event: Event):
 """Publish an event to all subscribed listeners"""
 with self.lock:
 self.event_history.append(event)

 print(f"\n📢 Publishing: {event}")

 # Notify all subscribed listeners
 with self.lock:
 listeners = self.listeners.get(event.event_type, []).copy()

 for listener in listeners:
 try:
 listener.on_event(event)
 except Exception as e:
 print(f" ❌ Error in {listener.listener_name}: {e}")

 def get_event_history(self, event_type: str = None) -> List[Event]:
 """Get event history, optionally filtered by type"""
 with self.lock:
 if event_type:
 return [e for e in self.event_history if e.event_type == event_type]
 return self.event_history.copy()

# ============================================
# IoT System Components (Event Listeners)
# ============================================

class MotionSensor(EventListener):
 """Motion sensor that publishes events"""

 def __init__(self, sensor_id: str, event_manager: EventManager):
 self.sensor_id = sensor_id
 self.event_manager = event_manager
 self.is_active = True

 @property
 def listener_name(self) -> str:
 return f"MotionSensor-{self.sensor_id}"

 def on_event(self, event: Event):
 # Motion sensors typically don't respond to events
 pass

 def detect_motion(self):
 """Simulate motion detection"""
 event = Event(
 event_type="MOTION_DETECTED",
 source=self.sensor_id,
 data={"location": f"Room-{self.sensor_id[-1]}", "confidence": 0.95}
 )
 self.event_manager.publish(event)

class SmartLight(EventListener):
 """Smart light that responds to motion events"""

 def __init__(self, light_id: str, event_manager: EventManager):
 self.light_id = light_id
 self.event_manager = event_manager
 self.is_on = False
 self.brightness = 0

 @property
 def listener_name(self) -> str:
 return f"SmartLight-{self.light_id}"

 def on_event(self, event: Event):
 if event.event_type == "MOTION_DETECTED":
 print(f" 💡 {self.listener_name}: Motion detected! Turning on.")
 self.turn_on()

 # Publish light turned on event
 self.event_manager.publish(Event(
 event_type="LIGHT_STATE_CHANGED",
 source=self.light_id,
 data={"state": "on", "brightness": self.brightness}
 ))

 def turn_on(self, brightness: int = 100):
 self.is_on = True
 self.brightness = brightness
 print(f" 💡 Light {self.light_id} ON (brightness: {brightness}%)")

 def turn_off(self):
 self.is_on = False
 self.brightness = 0
 print(f" 💡 Light {self.light_id} OFF")

class SecurityCamera(EventListener):
 """Security camera that records on motion"""

 def __init__(self, camera_id: str, event_manager: EventManager):
 self.camera_id = camera_id
 self.event_manager = event_manager
 self.is_recording = False

 @property
 def listener_name(self) -> str:
 return f"SecurityCamera-{self.camera_id}"

 def on_event(self, event: Event):
 if event.event_type == "MOTION_DETECTED":
 print(f" 📹 {self.listener_name}: Starting recording!")
 self.is_recording = True

 # Simulate recording duration
 time.sleep(0.1)
 self.is_recording = False
 print(f" 📹 {self.listener_name}: Recording stopped.")

class TemperatureSensor(EventListener):
 """Temperature sensor with threshold alerts"""

 def __init__(self, sensor_id: str, event_manager: EventManager, threshold: float = 30.0):
 self.sensor_id = sensor_id
 self.event_manager = event_manager
 self.threshold = threshold

 @property
 def listener_name(self) -> str:
 return f"TempSensor-{self.sensor_id}"

 def on_event(self, event: Event):
 pass # Temperature sensors publish, don't subscribe

 def read_temperature(self):
 """Simulate temperature reading"""
 temp = random.uniform(20, 35) # Random temp between 20-35°C

 event = Event(
 event_type="TEMPERATURE_READING",
 source=self.sensor_id,
 data={"temperature": temp, "unit": "°C"}
 )
 self.event_manager.publish(event)

 # Check threshold
 if temp > self.threshold:
 self.event_manager.publish(Event(
 event_type="TEMPERATURE_HIGH",
 source=self.sensor_id,
 data={"temperature": temp, "threshold": self.threshold}
 ))

class AlertSystem(EventListener):
 """Central alert system for critical events"""

 def __init__(self, event_manager: EventManager):
 self.event_manager = event_manager

 @property
 def listener_name(self) -> str:
 return "AlertSystem"

 def on_event(self, event: Event):
 if event.event_type == "TEMPERATURE_HIGH":
 temp = event.data['temperature']
 threshold = event.data['threshold']
 print(f" 🚨 ALERT: High temperature! {temp:.1f}°C exceeds threshold {threshold}°C")

 elif event.event_type == "MOTION_DETECTED":
 location = event.data.get('location', 'Unknown')
 print(f" 🚨 ALERT: Motion detected at {location}")

class SmartHomeController(EventListener):
 """Main controller that coordinates all components"""

 def __init__(self, controller_id: str, event_manager: EventManager):
 self.controller_id = controller_id
 self.event_manager = event_manager

 @property
 def listener_name(self) -> str:
 return f"Controller-{self.controller_id}"

 def on_event(self, event: Event):
 print(f" 🎛️ {self.listener_name}: Logging event - {event.event_type}")

# ============================================
# Demo Execution
# ============================================

def main():
 print("=" * 60)
 print("Event-Driven IoT Smart Home System")
 print("=" * 60)

 # Create event manager
 event_manager = EventManager()

 # Create IoT components
 motion_sensor = MotionSensor("MOT-001", event_manager)
 smart_light = SmartLight("LIGHT-001", event_manager)
 security_camera = SecurityCamera("CAM-001", event_manager)
 temp_sensor = TemperatureSensor("TEMP-001", event_manager, threshold=30.0)
 alert_system = AlertSystem(event_manager)
 controller = SmartHomeController("CTRL-001", event_manager)

 print("\n--- Subscribing Components to Events ---\n")

 # Subscribe components to events
 event_manager.subscribe("MOTION_DETECTED", smart_light)
 event_manager.subscribe("MOTION_DETECTED", security_camera)
 event_manager.subscribe("MOTION_DETECTED", alert_system)
 event_manager.subscribe("MOTION_DETECTED", controller)

 event_manager.subscribe("TEMPERATURE_HIGH", alert_system)
 event_manager.subscribe("TEMPERATURE_HIGH", controller)

 event_manager.subscribe("LIGHT_STATE_CHANGED", controller)

 print("\n--- Simulating IoT Events ---\n")

 # Simulate motion detection
 print("1. Simulating motion detection:")
 motion_sensor.detect_motion()
 time.sleep(0.2)

 # Simulate temperature readings
 print("\n2. Simulating temperature readings:")
 for i in range(3):
 temp_sensor.read_temperature()
 time.sleep(0.1)

 print("\n--- Event History ---")
 history = event_manager.get_event_history()
 print(f"Total events published: {len(history)}")
 for event in history:
 print(f" - {event.event_type} from {event.source}")

if __name__ == "__main__":
 main()

/*
 * IoT State Machine Implementation in C
 * Designed for embedded systems and resource-constrained IoT devices
 */

#include <stdio.h>
#include <string.h>
#include <stdlib.h>

/* ============================================
 * State Machine Data Structures
 * ============================================ */

// Maximum number of states and transitions
#define MAX_STATES 10
#define MAX_TRANSITIONS 20
#define MAX_NAME_LENGTH 32

// State enumeration
typedef enum {
 STATE_RED = 0,
 STATE_YELLOW = 1,
 STATE_GREEN = 2,
 STATE_COUNT
} TrafficLightState;

// Event enumeration 
typedef enum {
 EVENT_TIMER_EXPIRED = 0,
 EVENT_EMERGENCY = 1,
 EVENT_RESET = 2,
 EVENT_COUNT
} IoTEvent;

// State handler function pointer type
typedef void (*StateHandler)(void);

// Transition action function pointer type
typedef void (*TransitionAction)(IoTEvent event);

// State structure
typedef struct {
 char name[MAX_NAME_LENGTH];
 StateHandler on_enter;
 StateHandler on_exit;
 int active;
} IoTState;

// Transition structure
typedef struct {
 TrafficLightState from_state;
 IoTEvent event;
 TrafficLightState to_state;
 TransitionAction action;
 int valid;
} StateTransition;

// Main state machine structure
typedef struct {
 IoTState states[MAX_STATES];
 StateTransition transitions[MAX_TRANSITIONS];
 TrafficLightState current_state;
 int state_count;
 int transition_count;
} IoTStateMachine;

/* ============================================
 * State Handlers
 * ============================================ */

void handle_red_enter(void) {
 printf("🚦 RED LIGHT - Stop vehicles\n");
}

void handle_red_exit(void) {
 printf(" Exiting RED state\n");
}

void handle_yellow_enter(void) {
 printf("🚦 YELLOW LIGHT - Prepare to stop\n");
}

void handle_yellow_exit(void) {
 printf(" Exiting YELLOW state\n");
}

void handle_green_enter(void) {
 printf("🚦 GREEN LIGHT - Go!\n");
}

void handle_green_exit(void) {
 printf(" Exiting GREEN state\n");
}

/* ============================================
 * Transition Actions
 * ============================================ */

void log_transition(IoTEvent event) {
 const char* event_names[] = {"TIMER_EXPIRED", "EMERGENCY", "RESET"};
 printf(" → Transition triggered by: %s\n", event_names[event]);
}

/* ============================================
 * State Machine Functions
 * ============================================ */

// Initialize state machine
void sm_init(IoTStateMachine* sm) {
 sm->state_count = 0;
 sm->transition_count = 0;
 sm->current_state = STATE_RED;

 // Initialize all states
 memset(sm->states, 0, sizeof(sm->states));
 memset(sm->transitions, 0, sizeof(sm->transitions));
}

// Add a state to the machine
void sm_add_state(IoTStateMachine* sm, const char* name, 
 StateHandler enter, StateHandler exit) {
 if (sm->state_count < MAX_STATES) {
 strncpy(sm->states[sm->state_count].name, name, MAX_NAME_LENGTH - 1);
 sm->states[sm->state_count].on_enter = enter;
 sm->states[sm->state_count].on_exit = exit;
 sm->states[sm->state_count].active = 1;
 sm->state_count++;
 }
}

// Add a transition
void sm_add_transition(IoTStateMachine* sm, TrafficLightState from, 
 IoTEvent event, TrafficLightState to, TransitionAction action) {
 if (sm->transition_count < MAX_TRANSITIONS) {
 sm->transitions[sm->transition_count].from_state = from;
 sm->transitions[sm->transition_count].event = event;
 sm->transitions[sm->transition_count].to_state = to;
 sm->transitions[sm->transition_count].action = action;
 sm->transitions[sm->transition_count].valid = 1;
 sm->transition_count++;
 }
}

// Process an event
TrafficLightState sm_process_event(IoTStateMachine* sm, IoTEvent event) {
 // Find matching transition
 for (int i = 0; i < sm->transition_count; i++) {
 if (sm->transitions[i].from_state == sm->current_state &&
 sm->transitions[i].event == event &&
 sm->transitions[i].valid) {

 TrafficLightState next_state = sm->transitions[i].to_state;

 // Execute exit handler
 if (sm->states[sm->current_state].on_exit != NULL) {
 sm->states[sm->current_state].on_exit();
 }

 // Execute transition action
 if (sm->transitions[i].action != NULL) {
 sm->transitions[i].action(event);
 }

 // Update state
 sm->current_state = next_state;

 // Execute enter handler
 if (sm->states[next_state].on_enter != NULL) {
 sm->states[next_state].on_enter();
 }

 return next_state;
 }
 }

 printf(" ⚠️ No valid transition for event in current state\n");
 return sm->current_state;
}

// Get current state name
const char* sm_get_state_name(IoTStateMachine* sm) {
 if (sm->current_state < sm->state_count) {
 return sm->states[sm->current_state].name;
 }
 return "UNKNOWN";
}

// Safety property check
int sm_check_safety(IoTStateMachine* sm) {
 return sm->current_state >= 0 && sm->current_state < STATE_COUNT;
}

/* ============================================
 * Main Program - Traffic Light Demo
 * ============================================ */

int main(void) {
 printf("==================================================\n");
 printf("IoT State Machine - Traffic Light (C Implementation)\n");
 printf("==================================================\n\n");

 // Create and initialize state machine
 IoTStateMachine traffic_light;
 sm_init(&traffic_light);

 // Add states
 sm_add_state(&traffic_light, "RED", handle_red_enter, handle_red_exit);
 sm_add_state(&traffic_light, "YELLOW", handle_yellow_enter, handle_yellow_exit);
 sm_add_state(&traffic_light, "GREEN", handle_green_enter, handle_green_exit);

 // Add normal cycle transitions
 sm_add_transition(&traffic_light, STATE_RED, EVENT_TIMER_EXPIRED, 
 STATE_GREEN, log_transition);
 sm_add_transition(&traffic_light, STATE_GREEN, EVENT_TIMER_EXPIRED, 
 STATE_YELLOW, log_transition);
 sm_add_transition(&traffic_light, STATE_YELLOW, EVENT_TIMER_EXPIRED, 
 STATE_RED, log_transition);

 // Add emergency transitions
 sm_add_transition(&traffic_light, STATE_GREEN, EVENT_EMERGENCY, 
 STATE_RED, log_transition);
 sm_add_transition(&traffic_light, STATE_YELLOW, EVENT_EMERGENCY, 
 STATE_RED, log_transition);
 sm_add_transition(&traffic_light, STATE_RED, EVENT_EMERGENCY, 
 STATE_RED, log_transition);

 // Set initial state
 traffic_light.current_state = STATE_RED;
 traffic_light.states[STATE_RED].on_enter();

 printf("\n--- Simulating Normal Traffic Light Cycle ---\n\n");

 // Simulate normal cycle
 sm_process_event(&traffic_light, EVENT_TIMER_EXPIRED);
 sm_process_event(&traffic_light, EVENT_TIMER_EXPIRED);
 sm_process_event(&traffic_light, EVENT_TIMER_EXPIRED);
 sm_process_event(&traffic_light, EVENT_TIMER_EXPIRED);

 printf("\n--- Testing Emergency Transition ---\n\n");
 sm_process_event(&traffic_light, EVENT_EMERGENCY);

 printf("\n--- Safety Property Verification ---\n");
 printf("Current State: %s\n", sm_get_state_name(&traffic_light));
 printf("Safety Check: %s\n", sm_check_safety(&traffic_light) ? "PASSED" : "FAILED");

 printf("\n==================================================\n");
 printf("Demo Complete\n");
 printf("==================================================\n");

 return 0;
}
